1	package dnsresolve
2	
3	import (
4		"context"
5		"crypto/tls"
6		"crypto/x509"
7		"encoding/binary"
8		"errors"
9		"fmt"
10		"io"
11		"net"
12		"net/netip"
13		"time"
14	
15		"golang.org/x/net/dns/dnsmessage"
16	)
17	
18	// dotPort is the IANA-assigned DNS-over-TLS port (RFC 7858 SS3).
19	const dotPort = "853"
20	
21	// dotTimeout bounds a single DoT lookup (dial + TLS handshake + query write +
22	// response read), in addition to whatever deadline the caller's context
23	// already carries.
24	const dotTimeout = 5 * time.Second
25	
26	// dotMaxMessageSize mirrors dohMaxMessageSize: RFC 1035 SS4.2.2 bounds any
27	// legal DNS message to this size, so a length prefix claiming more is
28	// rejected without being trusted or buffered.
29	const dotMaxMessageSize = 65535
30	
31	// DoTResolver resolves hostnames via DNS-over-TLS (RFC 7858): it dials the
32	// configured server on port 853 with crypto/tls (verifying the presented
33	// certificate against the server name), and exchanges dnsmessage-encoded A
34	// and AAAA queries framed with the RFC 7858 2-byte big-endian length prefix.
35	//
36	// v1 dials one fresh TLS connection per family per Lookup call — lookups run
37	// at seconds cadence, not hot-path, so connection reuse is not worth the
38	// added complexity yet.
39	type DoTResolver struct {
40		addr      string // dial address, "host:853" (or a test-injected host:port)
41		tlsConfig *tls.Config
42	}
43	
44	var _ Resolver = (*DoTResolver)(nil)
45	
46	// NewDoTResolver returns a Resolver that queries server over DNS-over-TLS on
47	// port 853; server is used both as the dial target and as the TLS server
48	// name verified against the presented certificate. Certificate trust uses
49	// the platform's standard root CA store — there is no production knob to
50	// disable certificate verification.
51	func NewDoTResolver(server string) (*DoTResolver, error) {
52		return newDoTResolver(net.JoinHostPort(server, dotPort), server, nil)
53	}
54	
55	// newDoTResolver is the unexported constructor seam: addr is the dial
56	// target (host:port), serverName is the TLS server name verified against
57	// the presented certificate, and a non-nil roots pool overrides the
58	// platform trust store with roots. It exists ONLY for tests in this
59	// package, mirroring newDoHResolver — tests dial a loopback host:port while
60	// still exercising real certificate-name verification by passing a
61	// serverName that differs from addr's host.
62	func newDoTResolver(addr, serverName string, roots *x509.CertPool) (*DoTResolver, error) {
63		if serverName == "" {
64			return nil, errors.New("dnsresolve: DoT server name must not be empty")
65		}
66		return &DoTResolver{
67			addr: addr,
68			tlsConfig: &tls.Config{
69				RootCAs:    roots,
70				ServerName: serverName,
71				MinVersion: tls.VersionTLS12,
72			},
73		}, nil
74	}
75	
76	// Lookup implements Resolver. It queries A and AAAA for host and merges the
77	// results; a family that answers NXDOMAIN is tolerated as long as the other
78	// family answers. Any other per-family error (dial/TLS failure, timeout,
79	// truncated frame, malformed response) fails the whole lookup. An empty
80	// final addr set — both families NXDOMAIN, or a NOERROR/zero-answer
81	// (NODATA) response for both — is also an error (NXDomainError or
82	// NoDataError respectively), never a silent ([], nil). Matches DoHResolver's
83	// error taxonomy and empty-result handling exactly.
84	func (d *DoTResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
85		var (
86			addrs    []netip.Addr
87			minTTL   time.Duration
88			haveTTL  bool
89			nxdomain error
90		)
91	
92		for _, qtype := range [...]dnsmessage.Type{dnsmessage.TypeA, dnsmessage.TypeAAAA} {
93			famAddrs, famMinTTL, famHaveTTL, err := d.queryFamily(ctx, host, qtype)
94			if err != nil {
95				var nx *NXDomainError
96				if errors.As(err, &nx) {
97					nxdomain = err
98					continue
99				}
100				return nil, 0, false, err
101			}
102	
103			addrs = append(addrs, famAddrs...)
104			if famHaveTTL && (!haveTTL || famMinTTL < minTTL) {
105				minTTL = famMinTTL
106				haveTTL = true
107			}
108		}
109	
110		if len(addrs) == 0 {
111			if nxdomain != nil {
