138			Config:    d.tlsConfig,
139		}
140		conn, err := dialer.DialContext(ctx, "tcp", d.addr)
141		if err != nil {
142			if isTimeoutErr(err) {
143				return nil, 0, false, &TimeoutError{Endpoint: d.addr, Err: err}
144			}
145			return nil, 0, false, fmt.Errorf("dnsresolve: DoT dial to %s failed: %w", d.addr, err)
146		}
147		defer conn.Close()
148	
149		if err := conn.SetDeadline(deadline); err != nil {
150			return nil, 0, false, fmt.Errorf("dnsresolve: setting DoT connection deadline: %w", err)
151		}
152	
153		if err := writeDoTFrame(conn, query); err != nil {
154			if isTimeoutErr(err) {
