package dnsresolve

import (
	"context"
	"crypto/tls"
	"crypto/x509"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"net"
	"net/netip"
	"time"

	"golang.org/x/net/dns/dnsmessage"
)

// dotPort is the IANA-assigned DNS-over-TLS port (RFC 7858 SS3).
const dotPort = "853"

// dotTimeout bounds a single DoT lookup (dial + TLS handshake + query write +
// response read), in addition to whatever deadline the caller's context
// already carries.
const dotTimeout = 5 * time.Second

// dotMaxMessageSize mirrors dohMaxMessageSize: RFC 1035 SS4.2.2 bounds any
// legal DNS message to this size, so a length prefix claiming more is
// rejected without being trusted or buffered.
const dotMaxMessageSize = 65535

// DoTResolver resolves hostnames via DNS-over-TLS (RFC 7858): it dials the
// configured server on port 853 with crypto/tls (verifying the presented
// certificate against the server name), and exchanges dnsmessage-encoded A
// and AAAA queries framed with the RFC 7858 2-byte big-endian length prefix.
//
// v1 dials one fresh TLS connection per family per Lookup call — lookups run
// at seconds cadence, not hot-path, so connection reuse is not worth the
// added complexity yet.
type DoTResolver struct {
	addr      string // dial address, "host:853" (or a test-injected host:port)
	tlsConfig *tls.Config
}

var _ Resolver = (*DoTResolver)(nil)

// NewDoTResolver returns a Resolver that queries server over DNS-over-TLS on
// port 853; server is used both as the dial target and as the TLS server
// name verified against the presented certificate. Certificate trust uses
// the platform's standard root CA store — there is no production knob to
// disable certificate verification.
func NewDoTResolver(server string) (*DoTResolver, error) {
	return newDoTResolver(net.JoinHostPort(server, dotPort), server, nil)
}

// newDoTResolver is the unexported constructor seam: addr is the dial
// target (host:port), serverName is the TLS server name verified against
// the presented certificate, and a non-nil roots pool overrides the
// platform trust store with roots. It exists ONLY for tests in this
// package, mirroring newDoHResolver — tests dial a loopback host:port while
// still exercising real certificate-name verification by passing a
// serverName that differs from addr's host.
func newDoTResolver(addr, serverName string, roots *x509.CertPool) (*DoTResolver, error) {
	if serverName == "" {
		return nil, errors.New("dnsresolve: DoT server name must not be empty")
	}
	return &DoTResolver{
		addr: addr,
		tlsConfig: &tls.Config{
			RootCAs:    roots,
			ServerName: serverName,
			MinVersion: tls.VersionTLS12,
		},
	}, nil
}

// Lookup implements Resolver. It queries A and AAAA for host and merges the
// results; a family that answers NXDOMAIN is tolerated as long as the other
// family answers. Any other per-family error (dial/TLS failure, timeout,
// truncated frame, malformed response) fails the whole lookup. An empty
// final addr set — both families NXDOMAIN, or a NOERROR/zero-answer
// (NODATA) response for both — is also an error (NXDomainError or
// NoDataError respectively), never a silent ([], nil). Matches DoHResolver's
// error taxonomy and empty-result handling exactly.
func (d *DoTResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
	var (
		addrs    []netip.Addr
		minTTL   time.Duration
		haveTTL  bool
		nxdomain error
	)

	for _, qtype := range [...]dnsmessage.Type{dnsmessage.TypeA, dnsmessage.TypeAAAA} {
		famAddrs, famMinTTL, famHaveTTL, err := d.queryFamily(ctx, host, qtype)
		if err != nil {
			var nx *NXDomainError
			if errors.As(err, &nx) {
				nxdomain = err
				continue
			}
			return nil, 0, false, err
		}

		addrs = append(addrs, famAddrs...)
		if famHaveTTL && (!haveTTL || famMinTTL < minTTL) {
			minTTL = famMinTTL
			haveTTL = true
		}
	}

	if len(addrs) == 0 {
		if nxdomain != nil {
			return nil, 0, false, nxdomain
		}
		return nil, 0, false, &NoDataError{Endpoint: d.addr, Host: host}
	}

	return addrs, minTTL, haveTTL, nil
}

// queryFamily runs a single A or AAAA query over one fresh DoT connection:
// dial + TLS handshake, write the length-prefixed query, read the
// length-prefixed answer.
func (d *DoTResolver) queryFamily(ctx context.Context, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
	query, err := buildQuery(host, qtype)
	if err != nil {
		return nil, 0, false, fmt.Errorf("dnsresolve: encoding DoT query for %q: %w", host, err)
	}

	// Bound the whole exchange to dotTimeout, further bounded by the
	// caller's context deadline when it is sooner.
	deadline := time.Now().Add(dotTimeout)
	if ctxDeadline, ok := ctx.Deadline(); ok && ctxDeadline.Before(deadline) {
		deadline = ctxDeadline
	}

	dialer := &tls.Dialer{
		NetDialer: &net.Dialer{Deadline: deadline},
		Config:    d.tlsConfig,
	}
	conn, err := dialer.DialContext(ctx, "tcp", d.addr)
	if err != nil {
		if isTimeoutErr(err) {
			return nil, 0, false, &TimeoutError{Endpoint: d.addr, Err: err}
		}
		return nil, 0, false, fmt.Errorf("dnsresolve: DoT dial to %s failed: %w", d.addr, err)
	}
	defer conn.Close()

	if err := conn.SetDeadline(deadline); err != nil {
		return nil, 0, false, fmt.Errorf("dnsresolve: setting DoT connection deadline: %w", err)
	}

	if err := writeDoTFrame(conn, query); err != nil {
		if isTimeoutErr(err) {
			return nil, 0, false, &TimeoutError{Endpoint: d.addr, Err: err}
		}
		return nil, 0, false, fmt.Errorf("dnsresolve: writing DoT query to %s failed: %w", d.addr, err)
	}

	body, err := readDoTFrame(conn)
	if err != nil {
		if isTimeoutErr(err) {
			return nil, 0, false, &TimeoutError{Endpoint: d.addr, Err: err}
		}
		return nil, 0, false, &MalformedResponseError{Endpoint: d.addr, Err: err}
	}

	return parseAnswer(d.addr, body, host, qtype)
}

// writeDoTFrame writes msg to w prefixed with its RFC 7858 2-byte
// big-endian length.
func writeDoTFrame(w io.Writer, msg []byte) error {
	if len(msg) > dotMaxMessageSize {
		return fmt.Errorf("dnsresolve: DoT query exceeds max DNS message size of %d bytes", dotMaxMessageSize)
	}
	frame := make([]byte, 2+len(msg))
	binary.BigEndian.PutUint16(frame, uint16(len(msg)))
	copy(frame[2:], msg)
	_, err := w.Write(frame)
	return err
}

// readDoTFrame reads one RFC 7858 length-prefixed DNS message from r. A
// connection that closes (or times out) before the declared length is fully
// read yields a wrapped io.ErrUnexpectedEOF/timeout, which the caller
// classifies into a typed TimeoutError or MalformedResponseError.
func readDoTFrame(r io.Reader) ([]byte, error) {
	var lenBuf [2]byte
	if _, err := io.ReadFull(r, lenBuf[:]); err != nil {
		if isTimeoutErr(err) {
			return nil, err
		}
		return nil, fmt.Errorf("truncated length prefix: %w", err)
	}

	n := binary.BigEndian.Uint16(lenBuf[:])
	body := make([]byte, n)
	if _, err := io.ReadFull(r, body); err != nil {
		if isTimeoutErr(err) {
			return nil, err
		}
		return nil, fmt.Errorf("truncated %d-byte message: %w", n, err)
	}
	return body, nil
}

package dnsresolve

import (
	"bytes"
	"context"
	"crypto/tls"
	"crypto/x509"
	"errors"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/netip"
	"net/url"
	"time"

	"golang.org/x/net/dns/dnsmessage"
)

// dohMediaType is the RFC 8484 wire-format media type for both the request
// body and the expected response body.
const dohMediaType = "application/dns-message"

// dohTimeout bounds a single DoH POST round trip (request send + response
// read). It applies via http.Client.Timeout in addition to whatever deadline
// the caller's context already carries.
const dohTimeout = 5 * time.Second

// dohMaxMessageSize is the maximum wire size of a DNS message (RFC 1035
// SS4.2.2 / RFC 8484): the response body is capped to this to bound memory
// use against a malicious or misbehaving DoH server, regardless of any
// Content-Length header it claims.
const dohMaxMessageSize = 65535

// DoHResolver resolves hostnames via DNS-over-HTTPS (RFC 8484): it encodes A
// and AAAA queries with golang.org/x/net/dns/dnsmessage, POSTs each to a
// configured DoH URL, and extracts the answer addrs and minimum TTL.
//
// Residual leak: the DoH provider (and any network observer) sees the TLS
// SNI of the DoH URL's host and the timing/size of each request — DoH hides
// the query *content* from on-path observers, not the fact that this host is
// talking to that DoH provider.
type DoHResolver struct {
	url    string
	client *http.Client
}

var _ Resolver = (*DoHResolver)(nil)

// NewDoHResolver returns a Resolver that POSTs DNS-over-HTTPS queries to
// rawURL (which must be an https:// URL). Certificate trust uses the
// platform's standard root CA store — there is no production knob to disable
// certificate verification.
func NewDoHResolver(rawURL string) (*DoHResolver, error) {
	return newDoHResolver(rawURL, nil)
}

// newDoHResolver is the unexported constructor seam: a non-nil roots pool
// overrides the platform trust store with roots, for injecting a test CA
// (e.g. from httptest.NewTLSServer) — it exists ONLY for tests in this
// package. Production code always goes through NewDoHResolver, which passes
// roots=nil and gets tls.Config's default (the system pool).
func newDoHResolver(rawURL string, roots *x509.CertPool) (*DoHResolver, error) {
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return nil, fmt.Errorf("dnsresolve: invalid DoH URL %q: %w", rawURL, err)
	}
	if parsed.Scheme != "https" {
		return nil, fmt.Errorf("dnsresolve: DoH URL %q must use https, got scheme %q", rawURL, parsed.Scheme)
	}

	transport := &http.Transport{
		// No proxy surprise: never route DoH queries through an
		// environment-configured (HTTP_PROXY/HTTPS_PROXY) proxy — a DoH
		// resolver silently redirected through an unexpected intermediary
		// would defeat the point of choosing a specific trusted provider.
		Proxy: nil,
		TLSClientConfig: &tls.Config{
			RootCAs:    roots,
			MinVersion: tls.VersionTLS12,
		},
		// HTTP/2 ok: Go only auto-negotiates h2 over a custom
		// TLSClientConfig when this is set explicitly.
		ForceAttemptHTTP2: true,
	}

	return &DoHResolver{
		url: rawURL,
		client: &http.Client{
			Transport: transport,
			Timeout:   dohTimeout,
		},
	}, nil
}

// Lookup implements Resolver. It queries A and AAAA for host and merges the
// results; a family that answers NXDOMAIN is tolerated as long as the other
// family answers. Any other per-family error (transport failure, non-200,
// malformed response) fails the whole lookup. An empty final addr set — both
// families NXDOMAIN, or a NOERROR/zero-answer (NODATA) response for both —
// is also an error (NXDomainError or NoDataError respectively), never a
// silent ([], nil).
func (d *DoHResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
	var (
		addrs    []netip.Addr
		minTTL   time.Duration
		haveTTL  bool
		nxdomain error
	)

	for _, qtype := range [...]dnsmessage.Type{dnsmessage.TypeA, dnsmessage.TypeAAAA} {
		famAddrs, famMinTTL, famHaveTTL, err := d.queryFamily(ctx, host, qtype)
		if err != nil {
			var nx *NXDomainError
			if errors.As(err, &nx) {
				nxdomain = err
				continue
			}
			return nil, 0, false, err
		}

		addrs = append(addrs, famAddrs...)
		if famHaveTTL && (!haveTTL || famMinTTL < minTTL) {
			minTTL = famMinTTL
			haveTTL = true
		}
	}

	// An empty FINAL addr set is a failure, not a success: it covers both a
	// double-NXDOMAIN (below) and a NOERROR/zero-answer response (NODATA, or
	// a CNAME with no A/AAAA target) from one or both families. Returning
	// (nil, nil) here would diverge from SystemResolver, which surfaces a
	// no-such-host error from net.Resolver.LookupNetIP in the same
	// situation — callers must not see the two Resolver implementations
	// behave differently behind the same seam.
	if len(addrs) == 0 {
		if nxdomain != nil {
			return nil, 0, false, nxdomain
		}
		return nil, 0, false, &NoDataError{Endpoint: d.url, Host: host}
	}

	return addrs, minTTL, haveTTL, nil
}

// queryFamily runs a single A or AAAA query over DoH.
func (d *DoHResolver) queryFamily(ctx context.Context, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
	query, err := buildQuery(host, qtype)
	if err != nil {
		return nil, 0, false, fmt.Errorf("dnsresolve: encoding DoH query for %q: %w", host, err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, d.url, bytes.NewReader(query))
	if err != nil {
		return nil, 0, false, fmt.Errorf("dnsresolve: building DoH request to %s: %w", d.url, err)
	}
	req.Header.Set("Content-Type", dohMediaType)
	req.Header.Set("Accept", dohMediaType)

	resp, err := d.client.Do(req)
	if err != nil {
		if isTimeoutErr(err) {
			return nil, 0, false, &TimeoutError{Endpoint: d.url, Err: err}
		}
		return nil, 0, false, fmt.Errorf("dnsresolve: DoH POST to %s failed: %w", d.url, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, 0, false, &StatusError{URL: d.url, StatusCode: resp.StatusCode}
	}

	// Cap the read at dohMaxMessageSize+1: a DNS message can never legally
	// exceed dohMaxMessageSize bytes, so reading one extra byte lets us
	// detect and reject an oversized body without trusting an
	// attacker-controlled Content-Length or buffering an unbounded stream.
	body, err := io.ReadAll(io.LimitReader(resp.Body, dohMaxMessageSize+1))
	if err != nil {
		if isTimeoutErr(err) {
			return nil, 0, false, &TimeoutError{Endpoint: d.url, Err: err}
		}
		return nil, 0, false, &MalformedResponseError{Endpoint: d.url, Err: err}
	}
	if len(body) > dohMaxMessageSize {
		return nil, 0, false, &MalformedResponseError{
			Endpoint: d.url,
			Err:      fmt.Errorf("response body exceeds max DNS message size of %d bytes", dohMaxMessageSize),
		}
	}

	return parseAnswer(d.url, body, host, qtype)
}

// isTimeoutErr reports whether err represents a request that exceeded its
// deadline (context deadline or http.Client/net.Dialer timeout).
func isTimeoutErr(err error) bool {
	var netErr net.Error
	if errors.As(err, &netErr) && netErr.Timeout() {
		return true
	}
	return errors.Is(err, context.DeadlineExceeded)
}

// StatusError reports a DoH provider responding with a non-200 HTTP status.
type StatusError struct {
	URL        string
	StatusCode int
}

func (e *StatusError) Error() string {
	return fmt.Sprintf("dnsresolve: DoH %s returned HTTP status %d", e.URL, e.StatusCode)
}

