1	package dnsresolve
2	
3	import (
4		"context"
5		"crypto/x509"
6		"errors"
7		"io"
8		"net/http"
9		"net/http/httptest"
10		"net/netip"
11		"testing"
12		"time"
13	
14		"golang.org/x/net/dns/dnsmessage"
15	)
16	
17	// newCertPoolFromServer returns a CertPool trusting only srv's leaf
18	// certificate, mimicking how a caller injects a private/test CA via the
19	// unexported constructor seam.
20	func newCertPoolFromServer(t *testing.T, srv *httptest.Server) *x509.CertPool {
21		t.Helper()
22		pool := x509.NewCertPool()
23		pool.AddCert(srv.Certificate())
24		return pool
25	}
26	
27	// newDoHTestResolver builds a DoHResolver that trusts srv's certificate via
28	// the unexported test-only constructor seam (no InsecureSkipVerify).
29	func newDoHTestResolver(t *testing.T, srv *httptest.Server, path string) *DoHResolver {
30		t.Helper()
31		pool := newCertPoolFromServer(t, srv)
32		r, err := newDoHResolver(srv.URL+path, pool)
33		if err != nil {
34			t.Fatalf("newDoHResolver: unexpected error: %v", err)
35		}
36		return r
37	}
38	
39	func readDoHQuestion(t *testing.T, r *http.Request) (dnsmessage.Message, dnsmessage.Type) {
40		t.Helper()
41		if r.Method != http.MethodPost {
42			t.Fatalf("DoH request method = %s, want POST", r.Method)
43		}
44		if ct := r.Header.Get("Content-Type"); ct != dohMediaType {
45			t.Fatalf("DoH request Content-Type = %q, want %q", ct, dohMediaType)
46		}
47		body, err := io.ReadAll(r.Body)
48		if err != nil {
49			t.Fatalf("reading DoH request body: %v", err)
50		}
51		var msg dnsmessage.Message
52		if err := msg.Unpack(body); err != nil {
53			t.Fatalf("unpacking DoH request body: %v", err)
54		}
55		if len(msg.Questions) != 1 {
56			t.Fatalf("DoH request has %d questions, want 1", len(msg.Questions))
57		}
58		return msg, msg.Questions[0].Type
59	}
60	
61	func writeDoHAnswer(t *testing.T, w http.ResponseWriter, q dnsmessage.Question, answers []dnsmessage.Resource) {
62		t.Helper()
63		resp := dnsmessage.Message{
64			Header: dnsmessage.Header{
65				Response:           true,
66				RecursionAvailable: true,
67				RCode:              dnsmessage.RCodeSuccess,
68			},
69			Questions: []dnsmessage.Question{q},
70			Answers:   answers,
71		}
72		buf, err := resp.Pack()
73		if err != nil {
74			t.Fatalf("packing DoH response: %v", err)
75		}
76		w.Header().Set("Content-Type", dohMediaType)
77		if _, err := w.Write(buf); err != nil {
78			t.Fatalf("writing DoH response: %v", err)
79		}
80	}
81	
82	func aResource(t *testing.T, q dnsmessage.Question, ip [4]byte, ttl uint32) dnsmessage.Resource {
83		t.Helper()
84		return dnsmessage.Resource{
85			Header: dnsmessage.ResourceHeader{Name: q.Name, Type: dnsmessage.TypeA, Class: dnsmessage.ClassINET, TTL: ttl},
86			Body:   &dnsmessage.AResource{A: ip},
87		}
88	}
89	
90	func aaaaResource(t *testing.T, q dnsmessage.Question, ip [16]byte, ttl uint32) dnsmessage.Resource {
91		t.Helper()
92		return dnsmessage.Resource{
93			Header: dnsmessage.ResourceHeader{Name: q.Name, Type: dnsmessage.TypeAAAA, Class: dnsmessage.ClassINET, TTL: ttl},
94			Body:   &dnsmessage.AAAAResource{AAAA: ip},
95		}
96	}
97	
98	func TestDoHResolverLookupReturnsExpectedAddrsAndMinTTL(t *testing.T) {
99		srv := httptest.NewTLSServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
100			msg, qtype := readDoHQuestion(t, r)
101			q := msg.Questions[0]
102			switch qtype {
103			case dnsmessage.TypeA:
104				writeDoHAnswer(t, w, q, []dnsmessage.Resource{
105					aResource(t, q, [4]byte{192, 0, 2, 1}, 300),
106					aResource(t, q, [4]byte{192, 0, 2, 2}, 120),
107				})
