func TestDoHResolverTimeout(t *testing.T) {
	blockCh := make(chan struct{})

	srv := httptest.NewTLSServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		readDoHQuestion(t, r)
